document.addEventListener("DOMContentLoaded",(()=>{document.getElementById("selectedDate").innerHTML='<%= typeof appDate !== "undefined" ? appDate : "" %>',(async()=>{try{const e=await fetch("/api/appDateInUse"),t=await e.text();document.getElementById("selectedDate").innerHTML=`Ημ/νία Χρήσης : ${t.substring(9,11)}/${t.substring(6,8)}/${t.substring(1,5)}`}catch(e){}})()}));